import type { ComponentType, ReactNode, SVGProps } from "react";

// ---------------------------------------------------------------------------
// Shared icon interface
// ---------------------------------------------------------------------------

type SkillIconProps = { size?: number; className?: string };

// ---------------------------------------------------------------------------
// Simple Icons inline SVG wrapper (same pattern as BrandIcons.tsx)
// ---------------------------------------------------------------------------

function SkillIcon({
  size = 24,
  children,
  ...props
}: SVGProps<SVGSVGElement> & { size?: number; children: ReactNode }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="currentColor"
      aria-hidden="true"
      {...props}
    >
      {children}
    </svg>
  );
}

// ---------------------------------------------------------------------------
// Simple Icons — one component per skill
// ---------------------------------------------------------------------------

